const inputItems = $input.all(); // all items passed to this node
const results = [];

for (const item of inputItems) {
  const inputData = item.json;

  let processedData = {
    domain: null,
    targetUrl: '',
    totalBacklinks: 0,
    topBacklinks: [],
    summary: {
      avgRank: 0,
      dofollowCount: 0,
      nofollowCount: 0,
      brokenLinks: 0,
      avgSpamScore: 0
    },
    processed_at: new Date().toISOString(),
    error: null
  };

  try {
    if (inputData && inputData.tasks && inputData.tasks[0] && inputData.tasks[0].result && inputData.tasks[0].result[0]) {
      const result = inputData.tasks[0].result[0];
      const items = result.items || [];

      processedData.domain = result.target;
      processedData.targetUrl = result.target;
      processedData.totalBacklinks = result.total_count || 0;

      let totalRank = 0;
      let totalSpamScore = 0;

      items.forEach(item => {
        const backlink = {
          fromDomain: item.domain_from,
          fromUrl: item.url_from,
          anchor: item.anchor || 'No anchor text',
          rank: item.rank || 0,
          domainRank: item.domain_from_rank || 0,
          spamScore: item.backlink_spam_score || 0,
          dofollow: item.dofollow || false,
          isBroken: item.is_broken || false,
          firstSeen: item.first_seen,
          lastSeen: item.last_seen,
          linkType: item.item_type,
          pageTitle: item.page_from_title || 'Unknown'
        };

        processedData.topBacklinks.push(backlink);
        totalRank += backlink.rank;
        totalSpamScore += backlink.spamScore;

        backlink.dofollow ? processedData.summary.dofollowCount++ : processedData.summary.nofollowCount++;
        if (backlink.isBroken) processedData.summary.brokenLinks++;
      });

      if (items.length > 0) {
        processedData.summary.avgRank = Math.round(totalRank / items.length);
        processedData.summary.avgSpamScore = Math.round(totalSpamScore / items.length);
      }

    } else {
      processedData.error = 'Invalid API response format';
    }
  } catch (error) {
    processedData.error = `Processing error: ${error.message}`;
  }

  results.push({ json: processedData });
}

return results;

// Generate timestamp 24 hours BEFORE now (IST)
const IST_OFFSET = 5.5 * 60 * 60 * 1000; // IST offset in milliseconds
const date = new Date(Date.now() - 24 * 60 * 60 * 1000 + IST_OFFSET);

const pad = (n) => (n < 10 ? '0' + n : n);

const time = `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())} ${pad(date.getHours())}:${pad(date.getMinutes())}:${pad(date.getSeconds())} +05:30`;

console.log(time);

// Get all input clients
const clients = $input.all().map(item => item.json);

// Build grouped output
const result = [];

clients.forEach(client => {
  const clientData = {
    client_id: client.id,
    client_name: client.name,
    client_domains: []
  };

  (client.client_domains || []).forEach(domain => {
    if (!domain.rival_domains || domain.rival_domains.length === 0) return; // skip domains with no rivals

    clientData.client_domains.push({
      client_domain_id: domain.id,
      client_domain_title: domain.title,
      client_domain: domain.target_url,
      date: time ,
      rival_domains: domain.rival_domains.map(rival => ({
        id: rival.id,
        rival_domain_title: rival.title,
        rival_domain: rival.target_url,
        date: time // 24h before current UTC time
      }))
    });
  });

  // only push clients that actually have domains with rivals
  if (clientData.client_domains.length > 0) {
    result.push(clientData);
  }
});

// Return as n8n items
return result.map(r => ({ json: r }));

// Input
const data = $input.all(); 
const clientDomains = $('Current Client Domain List').all().map(i => i.json);

const normalize = str => str?.replace(/\/+$/, "").trim().toLowerCase();

const findDomain = (id, url, rivalUrl) => {
  return clientDomains.find(d => 
    Number(d.client_domain_id) === Number(id) &&
    normalize(d.client_domain) === normalize(url) &&
    normalize(d.rival_domain) === normalize(rivalUrl)
  );
};

const backlinkPayloads = [];

for (const item of data) {
  const backlinkParsed = item.json;
  if (!backlinkParsed) continue;

  const accepted = backlinkParsed.data?.accepted || [];
  const rejected = backlinkParsed.data?.rejected || [];

  const domainId = backlinkParsed.domain_id;
  const domainUrl = backlinkParsed.domain;
  const rivalUrl = backlinkParsed.data?.domain;

  const clientMatch = findDomain(domainId, domainUrl, rivalUrl);

  if (!clientMatch) {
    console.log("No match found for:", domainId, domainUrl, rivalUrl);
    continue; // or handle gracefully
  }

  const pushLinks = (arr, status) => {
    if (!Array.isArray(arr)) return;

    for (const link of arr) {
      backlinkPayloads.push({
        // report_id: reportId,
        client_id: $input.first().json.clientId,
        domain_id : domainId,

        target_domain: clientMatch.rival_domain_title,
        target_url: rivalUrl,

        domain: clientMatch.client_domain_title,
        domain_url: clientMatch.client_domain,

        from_domain: link.domain || link.fromDomain,
        from_url: link.fromUrl,
        url: link.url,
        anchor: link.anchor ?? null,
        page_title: link.pageTitle ?? null,
        link_type: "contextual",

        rank: link.rank ?? null,
        domain_rank: link.domainRank ?? null,
        spam_score: link.spamScore ?? null,
        do_follow: link.dofollow ? 1 : 0,
        tier: parseInt(link.tier?.replace("Tier ", ""), 10) || 0,
        score: link.score ?? 0,
        is_broken: link.isBroken ? 1 : 0,

        status,
        reason: link.reason ?? null,

        first_seen: link.firstSeen ? new Date(link.firstSeen).toISOString().slice(0, 19).replace('T', ' ') : null,
        last_seen: link.lastSeen ? new Date(link.lastSeen).toISOString().slice(0, 19).replace('T', ' ') : null,
      });
    }
  };

  pushLinks(accepted, "accepted");
  pushLinks(rejected, "rejected");
}

return backlinkPayloads.map(b => ({
  json: {
    api: "backlinkdatum/store",
    payload: b
  }
}));

