                        <td style="border:1px solid #e5e7eb; padding:12px 8px; vertical-align:top; font-size:11px; color:#4a5568; word-break:break-all;">
                            ${truncateUrl(link.url, 30)}
                        </td>
                        <td style="border:1px solid #e5e7eb; padding:12px 8px; vertical-align:top; font-size:11px; color:#6b7280;">
                            ${link.reason}
                        </td>
