      `;
    });

    html += `
                </tbody>
            </table>
        </div>
    `;
  } else {
    html += `
        <div style="padding:20px; border-bottom:1px solid #f3f4f6;">
            <div style="background-color:#10b981; color:#ffffff; padding:12px 16px; border-radius:6px; margin-bottom:15px; font-weight:600;">
                ✅ High-Quality Accepted Backlinks (0)
            </div>
            <div style="background-color:#f9fafb; padding:30px; text-align:center; border-radius:6px; color:#6b7280;">
                <div style="font-size:24px; margin-bottom:10px;">📊</div>
                <strong>No accepted backlinks found</strong><br style="font-size:12px;">
                <span style="font-size:12px;">This domain currently has no backlinks that meet our quality standards.</span>
            </div>
        </div>
    `;
  }

  // Rejected Links Section
  if (rejectedCount > 0) {
    html += `
        <div style="padding:20px;">
            <div style="background-color:#ef4444; color:#ffffff; padding:12px 16px; border-radius:6px; margin-bottom:15px; font-weight:600;">
                ❌ Low-Quality Rejected Backlinks (${rejectedCount})
            </div>

            <table width="100%" cellpadding="8" cellspacing="0" style="border-collapse:collapse; font-size:13px;">
                <thead>
                    <tr style="background-color:#f9fafb;">
                        <th style="border:1px solid #e5e7eb; padding:12px 8px; text-align:left; font-weight:600; color:#374151; font-size:11px; text-transform:uppercase;">Domain</th>
                        <th style="border:1px solid #e5e7eb; padding:12px 8px; text-align:left; font-weight:600; color:#374151; font-size:11px; text-transform:uppercase;">Source</th>
                        <th style="border:1px solid #e5e7eb; padding:12px 8px; text-align:left; font-weight:600; color:#374151; font-size:11px; text-transform:uppercase;">Rejection Reason</th>
                    </tr>
                </thead>
                <tbody>
    `;

    data.rejected.forEach(link => {
      html += `
                    <tr style="border-bottom:1px solid #f3f4f6;">
                        <td style="border:1px solid #e5e7eb; padding:12px 8px; vertical-align:top; font-weight:500; color:#1f2937;">
                            ${extractDomain(link.url)}
                        </td>
                        <td style="border:1px solid #e5e7eb; padding:12px 8px; vertical-align:top; font-size:11px; color:#4a5568; word-break:break-all;">
                            ${truncateUrl(link.url, 30)}
                        </td>
                        <td style="border:1px solid #e5e7eb; padding:12px 8px; vertical-align:top; font-size:11px; color:#6b7280;">
                            ${link.reason}
                        </td>
                    </tr>
      `;
    });

    html += `
                </tbody>
            </table>
        </div>
    `;
  } else {
    html += `
        <div style="padding:20px;">
            <div style="background-color:#ef4444; color:#ffffff; padding:12px 16px; border-radius:6px; margin-bottom:15px; font-weight:600;">
                ❌ Low-Quality Rejected Backlinks (0)
            </div>
            <div style="background-color:#f9fafb; padding:30px; text-align:center; border-radius:6px; color:#6b7280;">
                <div style="font-size:24px; margin-bottom:10px;">✨</div>
                <strong>No rejected backlinks</strong><br style="font-size:12px;">
                <span style="font-size:12px;">All analyzed backlinks for this domain meet quality standards.</span>
            </div>
        </div>
    `;
  }

  html += `
        </div>
  `;
});

html += `
    <!-- Footer -->
    <div style="background-color:#1f2937; color:#ffffff; text-align:center; padding:25px 20px; margin-top:30px; border-radius:0 0 8px 8px;">
        <div style="font-weight:600; margin-bottom:5px; color:#ffffff;">Professional SEO Backlink Analysis</div>
        <div style="opacity:0.85; font-size:13px; color:#ffffff;">Powered by Advanced SEO Analytics Engine</div>
    </div>
</div>
</body>
</html>
`;

// Generate Plain Text Version
let text = `
BACKLINK ANALYSIS REPORT
========================
Generated: ${currentDate}

SUMMARY
-------
• Total Domains: ${totalDomains}
• Total Links: ${totalLinks}
• Accepted: ${totalAccepted}
• Rejected: ${totalRejected}
• Quality Rate: ${totalLinks > 0 ? ((totalAccepted / totalLinks) * 100).toFixed(1) : 0}%

`;

Object.keys(domainData).forEach(domain => {
  const data = domainData[domain];
  text += `\n${'='.repeat(70)}\n`;
  text += `DOMAIN: ${domain}\n`;
  text += `Accepted: ${data.accepted.length} | Rejected: ${data.rejected.length}\n`;
  text += `${'='.repeat(70)}\n`;

  if (data.accepted.length > 0) {
    text += `\n✅ ACCEPTED BACKLINKS (${data.accepted.length}):\n`;
    text += `${'-'.repeat(70)}\n`;
    data.accepted.forEach((link, index) => {
      text += `${index + 1}. ${extractDomain(link.url)}\n`;
      text += `   URL: ${link.url}\n`;
      text += `   Score: ${link.score} | Rank: ${link.domain_rank} | Spam: ${link.spam_score}\n`;
      text += `   Follow: ${link.do_follow}\n`;
      text += `   Reason: ${link.reason}\n\n`;
    });
  }

  if (data.rejected.length > 0) {
    text += `\n❌ REJECTED BACKLINKS (${data.rejected.length}):\n`;
    text += `${'-'.repeat(70)}\n`;
    data.rejected.forEach((link, index) => {
      text += `${index + 1}. ${extractDomain(link.url)}\n`;
      text += `   URL: ${link.url}\n`;
      text += `   Rejection: ${link.reason}\n\n`;
    });
  }
});

text += `\n${'='.repeat(70)}\n`;
text += `Report Generated: ${new Date().toISOString()}\n`;
text += `${'='.repeat(70)}\n`;

const subject = `Backlink Analysis Report - ${currentDate} | ${totalDomains} Domains | ${totalAccepted} Accepted/${totalRejected} Rejected`;

return {
  json: {
    subject: subject,
    htmlBody: html,
    textBody: text,
    summary: {
      total_domains: totalDomains,
      total_links: totalLinks,
      accepted: totalAccepted,
      rejected: totalRejected,
      quality_rate: totalLinks > 0 ? ((totalAccepted / totalLinks) * 100).toFixed(1) : 0,
      generated_at: new Date().toISOString()
    }
  }
};
